import{_ as r,o as a,c as o,a2 as i}from"./chunks/framework.DtwafDNl.js";const u=JSON.parse('{"title":"Call Recordings","description":"","frontmatter":{},"headers":[],"relativePath":"features/recordings.md","filePath":"features/recordings.md"}'),d={name:"features/recordings.md"};function t(n,e,l,s,c,h){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="call-recordings" tabindex="-1">Call Recordings <a class="header-anchor" href="#call-recordings" aria-label="Permalink to &quot;Call Recordings&quot;">​</a></h1><p>Call Recordings give you a central library for reviewing recorded conversations. When recording is enabled for supported call paths, Callytics records bridged calls such as transfers, queue calls, and hunt group calls.</p><p>You can review calls directly in the browser, download them for external handling, or delete them when they are no longer needed.</p><p>Each recording includes useful context such as caller details, duration, and timestamp so you can find the right file without guessing from filenames.</p><h2 id="how-recordings-work" tabindex="-1">How recordings work <a class="header-anchor" href="#how-recordings-work" aria-label="Permalink to &quot;How recordings work&quot;">​</a></h2><h3 id="what-gets-recorded" tabindex="-1">What gets recorded <a class="header-anchor" href="#what-gets-recorded" aria-label="Permalink to &quot;What gets recorded&quot;">​</a></h3><p>Recording only happens on bridged calls. The following call paths support recording:</p><ul><li><strong>Transfer node</strong> — recording starts when <code>record_call</code> is enabled on the node</li><li><strong>Queue node</strong> — recording starts when <code>record_call</code> is enabled on the node</li><li><strong>Hunt Group node</strong> — recording starts when <code>record_call</code> is enabled on the node</li><li><strong>Direct outbound calls</strong> — recorded when <code>record_outbound_calls</code> is enabled in Settings</li></ul><p>IVR audio playback from the Play Audio node is never recorded, regardless of any recording settings elsewhere in the flow.</p><h3 id="bridge-recording" tabindex="-1">Bridge recording <a class="header-anchor" href="#bridge-recording" aria-label="Permalink to &quot;Bridge recording&quot;">​</a></h3><p>For Transfer, Queue, and Hunt Group calls, Stasis starts a bridge recording by calling the ARI endpoint:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>POST /ari/bridges/{bridgeId}/record</span></span></code></pre></div><p>This records the mixed audio of both call participants. Recordings are saved as <code>.wav</code> files.</p><h3 id="voicemail-recording" tabindex="-1">Voicemail recording <a class="header-anchor" href="#voicemail-recording" aria-label="Permalink to &quot;Voicemail recording&quot;">​</a></h3><p>For Voicemail nodes, Stasis calls the ARI channel recording endpoint directly on the caller&#39;s channel. Voicemail recordings are saved as <code>.ulaw</code> files.</p><h3 id="storage" tabindex="-1">Storage <a class="header-anchor" href="#storage" aria-label="Permalink to &quot;Storage&quot;">​</a></h3><p>All recording files are stored in the Docker volume <code>asterisk_recordings</code>. This volume is mounted at <code>/var/lib/asterisk/recording</code> in both the Asterisk container and the backend container. The backend reads files from this shared path when serving playback and download requests.</p><table tabindex="0"><thead><tr><th>Call type</th><th>Format</th><th>ARI endpoint used</th></tr></thead><tbody><tr><td>Transfer, Queue, Hunt Group</td><td><code>.wav</code></td><td><code>POST /ari/bridges/{bridgeId}/record</code></td></tr><tr><td>Voicemail</td><td><code>.ulaw</code></td><td>ARI channel recording endpoint</td></tr></tbody></table><h2 id="capabilities" tabindex="-1">Capabilities <a class="header-anchor" href="#capabilities" aria-label="Permalink to &quot;Capabilities&quot;">​</a></h2><ul><li>Automatic recording on supported bridged calls when enabled</li><li>Recording support for transfer calls</li><li>Recording support for queue calls</li><li>Recording support for hunt group calls</li><li>Paginated recordings library</li><li>Inline browser playback</li><li>Direct file download</li><li>Delete with confirmation</li><li>Recording metadata including caller, duration, and timestamp</li></ul>',20)])])}const p=r(d,[["render",t]]);export{u as __pageData,p as default};
